import{_ as r,r as t,o as n,c as i,f as o,a as e,b as l,d as s,e as c}from"./app-577c4561.js";const h={},d=e("div",{class:"custom-container tip"},[e("svg",{xmlns:"http://www.w3.org/2000/svg","xmlns:xlink":"http://www.w3.org/1999/xlink",viewBox:"0 0 24 24"},[e("g",{fill:"none",stroke:"currentColor","stroke-width":"2","stroke-linecap":"round","stroke-linejoin":"round"},[e("circle",{cx:"12",cy:"12",r:"9"}),e("path",{d:"M12 8h.01"}),e("path",{d:"M11 12h1v4h1"})])]),e("p",{class:"custom-container-title"},"TIP"),e("p",null,"因为自己被这中鼻炎困扰很久，所以写下这点生活小经验。")],-1),_=c('<h2 id="症状" tabindex="-1"><a class="header-anchor" href="#症状" aria-hidden="true">#</a> 症状</h2><ol><li>明显会感觉鼻腔发干，有时还伴有血丝（鼻粘膜破坏，鼻腔内皮肤比较薄弱）</li><li>鼻子又常常会不通气，并且鼻腔内有没有鼻涕（鼻黏膜破坏，无法分泌体液形成鼻涕来清洗鼻腔内的脏东西）</li><li>同时还伴有口渴的症状（鼻黏膜破坏，无法湿润空气，所以由咽喉来代替，所以会很渴，这也是为什么鼻炎患者为什么会同时伴有咽炎的原因）</li><li>更严重会头晕、头胀痛</li></ol><h2 id="治疗" tabindex="-1"><a class="header-anchor" href="#治疗" aria-hidden="true">#</a> 治疗</h2><h3 id="错误治疗" tabindex="-1"><a class="header-anchor" href="#错误治疗" aria-hidden="true">#</a> 错误治疗</h3><p>去医院，没有经验的医生经常给开一些“滴鼻净”之类的收缩鼻黏膜的滴鼻液，这是大忌，因为干燥性鼻炎患者的鼻黏膜已经严重破坏，这种药物除了可以让你的鼻子通气外，没有任何好处，还会让鼻炎加重。</p><h3 id="正确治疗" tabindex="-1"><a class="header-anchor" href="#正确治疗" aria-hidden="true">#</a> 正确治疗</h3><p>明白干燥性鼻炎的根本病因是鼻黏膜遭到破坏以后，就知道，干燥性鼻炎患者应该是要修复鼻黏膜，来恢复鼻子的正常功能，其他症状也就迎刃而解。<br></p><ul><li>这里推荐“生理性海水鼻炎喷剂”，可以去药店和网上购买。成分与体液成分差不多，它的目的就是辅助鼻子将炎症消除，促进鼻粘膜修复。</li><li>第二个是DHA（深海鱼油青少年使用版），这个方法是偶然一个医生告诉的。深海鱼油主要是用于促进儿童神经系统的发育，它的油性可以保持鼻腔湿润，同时又有促进鼻黏膜修复。（一次用一粒，分别挤到两个鼻腔内，按压鼻子让其均匀湿润，一星期一次，差不多4周可见效，不要多用，毕竟这不是专门用来治鼻炎用的）</li><li>薄荷油滴鼻液。这个一个是可以让鼻腔通常，另一个是它的油性可以保持鼻腔湿润。</li></ul><h2 id="保养" tabindex="-1"><a class="header-anchor" href="#保养" aria-hidden="true">#</a> 保养</h2><ol><li>干燥性鼻炎一般秋冬比较严重，当进入这两个季节后，当鼻子感觉不舒服的时候，就应该开始养成清洗鼻腔的习惯。清洗后，水分蒸发后会干，这时再给鼻腔滴点油性物质（薄荷油滴鼻液）来保持湿润。 <br> 清洗鼻腔一个可以选择专门的洗鼻盐，也可以使用生理盐水，清洗方法网上有，自行查找。</li><li>冬天要带口罩保暖</li></ol>',10),p={href:"http://recoluan.gitlab.io",target:"_blank",rel:"noopener noreferrer"},u=e("strong",null,"午后南杂",-1);function x(f,m){const a=t("ExternalLinkIcon");return n(),i("div",null,[d,o(" more "),_,e("p",null,[l("个人博客："),e("a",p,[u,s(a)])])])}const b=r(h,[["render",x],["__file","110901.html.vue"]]);export{b as default};
